+#### Align JSDoc before union type elements (#18833 by @fisker)
+
+<!-- prettier-ignore -->
+```tsx
+// Input
+type A =
+  |
+  /**
+   * Comment
+   */
+  a
+  | (b | c);
+type A2 =
+  |
+  // comment
+  a
+  | (b | c);
+
+// Prettier stable
+type A =
+  | /**
+   * Comment
+   */
+  a
+  | (b | c);
+type A2 =
+  | // comment
+  a
+  | (b | c);
+
+// Prettier main
+type A =
+  | /**
+     * Comment
+     */
+    a
+  | (b | c);
+type A2 =
+  | // comment
+    a
+  | (b | c);
+```
