+#### Fix required semicolon in `no-semi` mode (#18852 by @fisker)
+
+<!-- prettier-ignore -->
+```tsx
+// Input
+declare module "autoprefixer";
+{
+  alert()
+}
+declare function a();
+{
+  alert()
+}
+
+// Prettier stable (--no-semi)
+declare module "autoprefixer"
+{
+  alert()
+}
+declare function a()
+{
+  alert()
+}
+
+
+// Prettier main (--no-semi)
+declare module "autoprefixer";
+{
+  alert();
+}
+declare function a();
+{
+  alert();
+}
+```
